#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int a,b; scanf("%d %d", &a, &b);
        int s = a + b;
        int ans = (s < 3) ? 1 : (s <= 10) ? 2 : (s <= 60) ? 3 : 4;
        printf("%d\n", ans);
    }
    return 0;
}

